@Configuration
class SecurityConfig {

    @Bean
    SecurityFilterChain securityFilterChain(HttpSecurity http,
                                            SamlAuthenticationFilter samlAuthenticationFilter,
                                            SamlAuthenticationProvider samlAuthenticationProvider) throws Exception {
        http
            .csrf(csrf -> csrf.ignoringRequestMatchers(new AntPathRequestMatcher("/saml/acs", "POST")))
            .authorizeHttpRequests(auth -> auth
                .requestMatchers("/", "/error", "/saml/acs").permitAll()
                .anyRequest().authenticated()
            )
            .authenticationProvider(samlAuthenticationProvider)
            .addFilterAt(samlAuthenticationFilter, org.springframework.security.web.authentication.UsernamePasswordAuthenticationFilter.class)
            .logout(Customizer.withDefaults());

        return http.build();
    }

    @Bean
    SamlAuthenticationFilter samlAuthenticationFilter(org.springframework.security.authentication.AuthenticationManager authenticationManager) {
        SamlAuthenticationFilter filter = new SamlAuthenticationFilter("/saml/acs");
        filter.setAuthenticationManager(authenticationManager);
        filter.setAuthenticationSuccessHandler(samlAuthenticationSuccessHandler());
        return filter;
    }

    @Bean
    AuthenticationSuccessHandler samlAuthenticationSuccessHandler() {
        return (request, response, authentication) -> response.sendRedirect("/me");
    }
}

class SamlAuthenticationFilter extends AbstractAuthenticationProcessingFilter {

    protected SamlAuthenticationFilter(String defaultFilterProcessesUrl) {
        super(new AntPathRequestMatcher(defaultFilterProcessesUrl, HttpMethod.POST.name()));
    }

    @Override
    public Authentication attemptAuthentication(HttpServletRequest request, HttpServletResponse response)
        throws AuthenticationException, IOException, ServletException {

        String samlResponse = request.getParameter("SAMLResponse");
        if (!StringUtils.hasText(samlResponse)) {
            throw new BadCredentialsException("Missing SAMLResponse");
        }

        SamlAuthenticationToken authRequest = new SamlAuthenticationToken(samlResponse);
        authRequest.setDetails(authenticationDetailsSource.buildDetails(request));
        return this.getAuthenticationManager().authenticate(authRequest);
    }

    @Override
    protected void successfulAuthentication(HttpServletRequest request,
                                            HttpServletResponse response,
                                            FilterChain chain,
                                            Authentication authResult) throws IOException, ServletException {
        super.successfulAuthentication(request, response, chain, authResult);
    }
}

@Component
class SamlAuthenticationProvider implements AuthenticationProvider {

    private final SamlResponseParser samlResponseParser;

    SamlAuthenticationProvider(SamlResponseParser samlResponseParser) {
        this.samlResponseParser = samlResponseParser;
    }

    @Override
    public Authentication authenticate(Authentication authentication) throws AuthenticationException {
        SamlAuthenticationToken token = (SamlAuthenticationToken) authentication;
        SamlPrincipal principal = samlResponseParser.parse(token.getSamlResponse());

        List<SimpleGrantedAuthority> authorities = new ArrayList<>();
        authorities.add(new SimpleGrantedAuthority("ROLE_USER"));

        SamlAuthenticatedToken authenticated = new SamlAuthenticatedToken(principal, authorities);
        authenticated.setDetails(authentication.getDetails());
        return authenticated;
    }

    @Override
    public boolean supports(Class<?> authentication) {
        return SamlAuthenticationToken.class.isAssignableFrom(authentication);
    }
}

@Component
class SamlResponseParser {

    public SamlPrincipal parse(String base64SamlResponse) {
        try {
            byte[] decoded = Base64.getDecoder().decode(base64SamlResponse);
            String xml = new String(decoded, StandardCharsets.UTF_8);

            DocumentBuilderFactory factory = DocumentBuilderFactory.newInstance();
            factory.setNamespaceAware(true);
            factory.setFeature(XMLConstants.FEATURE_SECURE_PROCESSING, true);
            factory.setFeature("http://apache.org/xml/features/disallow-doctype-decl", true);
            factory.setFeature("http://xml.org/sax/features/external-general-entities", false);
            factory.setFeature("http://xml.org/sax/features/external-parameter-entities", false);
            factory.setAttribute(XMLConstants.ACCESS_EXTERNAL_DTD, "");
            factory.setAttribute(XMLConstants.ACCESS_EXTERNAL_SCHEMA, "");

            DocumentBuilder builder = factory.newDocumentBuilder();
            Document document = builder.parse(new InputSource(new StringReader(xml)));
            document.getDocumentElement().normalize();

            Element assertion = firstElementByLocalName(document, "Assertion");
            if (assertion == null) {
                throw new BadCredentialsException("No Assertion found in SAML response");
            }

            String nameId = extractNameId(assertion);
            if (!StringUtils.hasText(nameId)) {
                throw new BadCredentialsException("No NameID found in Assertion");
            }

            validateConditions(assertion);

            Map<String, List<String>> attributes = extractAttributes(assertion);

            return new SamlPrincipal(nameId, attributes);
        } catch (BadCredentialsException e) {
            throw e;
        } catch (Exception e) {
            throw new BadCredentialsException("Invalid SAML response", e);
        }
    }

    private void validateConditions(Element assertion) {
        Element conditions = firstChildElementByLocalName(assertion, "Conditions");
        if (conditions == null) {
            return;
        }

        String notBefore = conditions.getAttribute("NotBefore");
        String notOnOrAfter = conditions.getAttribute("NotOnOrAfter");
        Instant now = Instant.now();

        if (StringUtils.hasText(notBefore)) {
            Instant nb = Instant.parse(notBefore);
            if (now.isBefore(nb)) {
                throw new BadCredentialsException("Assertion not yet valid");
            }
        }

        if (StringUtils.hasText(notOnOrAfter)) {
            Instant noa = Instant.parse(notOnOrAfter);
            if (!now.isBefore(noa)) {
                throw new BadCredentialsException("Assertion expired");
            }
        }
    }

    private String extractNameId(Element assertion) {
        Element subject = firstChildElementByLocalName(assertion, "Subject");
        if (subject == null) {
            return null;
        }
        Element nameId = firstChildElementByLocalName(subject, "NameID");
        return nameId != null ? nameId.getTextContent().trim() : null;
    }

    private Map<String, List<String>> extractAttributes(Element assertion) {
        Map<String, List<String>> attributes = new LinkedHashMap<>();
        NodeList statements = assertion.getElementsByTagNameNS("*", "AttributeStatement");
        for (int i = 0; i < statements.getLength(); i++) {
            Node stmtNode = statements.item(i);
            if (stmtNode.getNodeType() != Node.ELEMENT_NODE) {
                continue;
            }
            Element stmt = (Element) stmtNode;
            NodeList attrNodes = stmt.getElementsByTagNameNS("*", "Attribute");
            for (int j = 0; j < attrNodes.getLength(); j++) {
                Node attrNode = attrNodes.item(j);
                if (attrNode.getNodeType() != Node.ELEMENT_NODE) {
                    continue;
                }
                Element attr = (Element) attrNode;
                String name = attr.getAttribute("Name");
                if (!StringUtils.hasText(name)) {
                    continue;
                }
                List<String> values = new ArrayList<>();
                NodeList valueNodes = attr.getElementsByTagNameNS("*", "AttributeValue");
                for (int k = 0; k < valueNodes.getLength(); k++) {
                    Node valueNode = valueNodes.item(k);
                    String value = valueNode.getTextContent();
                    if (value != null) {
                        values.add(value.trim());
                    }
                }
                attributes.put(name, values);
            }
        }
        return attributes;
    }

    private Element firstElementByLocalName(Document document, String localName) {
        NodeList nodes = document.getElementsByTagNameNS("*", localName);
        for (int i = 0; i < nodes.getLength(); i++) {
            Node node = nodes.item(i);
            if (node.getNodeType() == Node.ELEMENT_NODE) {
                return (Element) node;
            }
        }
        return null;
    }

    private Element firstChildElementByLocalName(Element parent, String localName) {
        NodeList children = parent.getElementsByTagNameNS("*", localName);
        for (int i = 0; i < children.getLength(); i++) {
            Node node = children.item(i);
            if (node.getNodeType() == Node.ELEMENT_NODE) {
                return (Element) node;
            }
        }
        return null;
    }
}

class SamlAuthenticationToken extends AbstractAuthenticationToken {

    private final String samlResponse;

    SamlAuthenticationToken(String samlResponse) {
        super(Collections.emptyList());
        this.samlResponse = samlResponse;
        setAuthenticated(false);
    }

    public String getSamlResponse() {
        return samlResponse;
    }

    @Override
    public Object getCredentials() {
        return samlResponse;
    }

    @Override
    public Object getPrincipal() {
        return null;
    }
}

class SamlAuthenticatedToken extends AbstractAuthenticationToken {

    private final SamlPrincipal principal;

    SamlAuthenticatedToken(SamlPrincipal principal, Collection<SimpleGrantedAuthority> authorities) {
        super(authorities);
        this.principal = principal;
        setAuthenticated(true);
    }

    @Override
    public Object getCredentials() {
        return "";
    }

    @Override
    public Object getPrincipal() {
        return principal;
    }
}

class SamlPrincipal {
    private final String nameId;
    private final Map<String, List<String>> attributes;

    SamlPrincipal(String nameId, Map<String, List<String>> attributes) {
        this.nameId = nameId;
        this.attributes = Collections.unmodifiableMap(new LinkedHashMap<>(attributes));
    }

    public String getNameId() {
        return nameId;
    }

    public Map<String, List<String>> getAttributes() {
        return attributes;
    }
}

@Component
class SamlSessionAttributeFilter extends org.springframework.web.filter.OncePerRequestFilter {

    @Override
    protected void doFilterInternal(HttpServletRequest request,
                                    HttpServletResponse response,
                                    FilterChain filterChain) throws ServletException, IOException {
        Authentication authentication = org.springframework.security.core.context.SecurityContextHolder.getContext().getAuthentication();
        if (authentication != null && authentication.isAuthenticated() && authentication.getPrincipal() instanceof SamlPrincipal principal) {
            HttpSession session = request.getSession(true);
            session.setAttribute("samlNameId", principal.getNameId());
            session.setAttribute("samlAttributes", principal.getAttributes());
        }
        filterChain.doFilter(request, response);
    }
}

@Configuration
class SessionFilterConfig {

    @Bean
    SecurityFilterChain sessionAttributeChain(HttpSecurity http, SamlSessionAttributeFilter samlSessionAttributeFilter) throws Exception {
        http.addFilterAfter(samlSessionAttributeFilter, org.springframework.security.web.context.SecurityContextHolderFilter.class);
        return http.build();
    }
}

@Controller
class HomeController {

    @GetMapping("/")
    @ResponseBody
    public String home() {
        return "SAML SP is running";
    }

    @GetMapping("/me")
    @ResponseBody
    public Map<String, Object> me(HttpServletRequest request, Authentication authentication) {
        Map<String, Object> result = new LinkedHashMap<>();
        result.put("authenticated", authentication != null && authentication.isAuthenticated());

        if (authentication != null && authentication.getPrincipal() instanceof SamlPrincipal principal) {
            result.put("nameId", principal.getNameId());
            result.put("attributes", principal.getAttributes());
        }

        HttpSession session = request.getSession(false);
        if (session != null) {
            Map<String, Object> sessionData = new LinkedHashMap<>();
            Enumeration<String> names = session.getAttributeNames();
            while (names.hasMoreElements()) {
                String name = names.nextElement();
                sessionData.put(name, session.getAttribute(name));
            }
            result.put("session", sessionData);
        }

        return result;
    }
}